{
  "name": "BILIMAI - Educational Quest",
  "description": "An AI-powered learning platform for children aged 9-14 preparing for NIS and BIL entrance exams, featuring gamified mechanics, step-by-step logic, and a supportive AI mentor."
}

export enum Subject {
  MATH = 'Математика',
  LOGIC = 'Логика',
  READING = 'Чтение',
  CRITICAL = 'Критическое мышление'
}

export interface Step {
  id: string;
  question: string;
  options: string[];
  correctAnswer: string;
  explanation: string;
}

export interface Problem {
  id: string;
  title: string;
  subject: Subject;
  difficulty: 'Легко' | 'Средне' | 'Сложно';
  steps: Step[];
}

export interface Achievement {
  id: string;
  title: string;
  description: string;
  icon: string;
  unlocked: boolean;
}

export interface UserStats {
  points: number;
  hearts: number;
  level: number;
  currentStreak: number;
  solvedCount: number;
  achievements: Achievement[];
}

export type View = 'dashboard' | 'lesson' | 'parent' | 'profile';

import { Subject, Achievement } from './types';

export const INITIAL_ACHIEVEMENTS: Achievement[] = [
  { id: 'logic-1', title: 'Логик', description: 'Реши 5 задач по логике', icon: '🧠', unlocked: false },
  { id: 'math-1', title: 'Математик', description: 'Реши 5 задач по математике', icon: '📐', unlocked: false },
  { id: 'step-by-step', title: 'Шаг за шагом', description: 'Пройди задачу без ошибок', icon: '👣', unlocked: false },
  { id: 'future-nis', title: 'Будущий ученик НИШ', description: 'Набери 1000 баллов', icon: '🎓', unlocked: false }
];

export const SUBJECT_INFO = {
  [Subject.MATH]: { color: 'bg-blue-500', icon: '📐' },
  [Subject.LOGIC]: { color: 'bg-purple-500', icon: '🧩' },
  [Subject.READING]: { color: 'bg-green-500', icon: '📚' },
  [Subject.CRITICAL]: { color: 'bg-orange-500', icon: '💡' },
};

import { GoogleGenAI, Type } from "@google/genai";
import { Subject, Problem } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateProblem = async (subject: Subject): Promise<Problem> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate a specialized multi-step educational problem for children (9-14) preparing for NIS/BIL exams in ${subject}. 
    The problem must have 3-4 sequential steps. Each step must build on the previous one.
    Format the response as a JSON object matching the Problem interface.
    The language must be Russian. Friendly and clear.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING },
          subject: { type: Type.STRING },
          difficulty: { type: Type.STRING },
          steps: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                question: { type: Type.STRING },
                options: { type: Type.ARRAY, items: { type: Type.STRING } },
                correctAnswer: { type: Type.STRING },
                explanation: { type: Type.STRING }
              },
              required: ["id", "question", "options", "correctAnswer", "explanation"]
            }
          }
        },
        required: ["id", "title", "subject", "difficulty", "steps"]
      }
    }
  });

  try {
    return JSON.parse(response.text);
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw e;
  }
};

export const getAIHint = async (problemTitle: string, currentStepText: string, subject: Subject): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `You are BilimAI, a friendly mentor. The student is solving a problem: "${problemTitle}". 
    They are stuck on this step: "${currentStepText}".
    Subject: ${subject}.
    CRITICAL RULE: DO NOT GIVE THE ANSWER.
    Instead, give a short, encouraging hint (in Russian) that explains the APPROACH or logic they should use. 
    Maximum 2-3 sentences. Use friendly, kid-appropriate language.`,
    config: {
      temperature: 0.7,
      topP: 0.9
    }
  });

  return response.text.trim();
};

