export const speakText = async (text: string): Promise<void> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Скажи по-доброму: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const audioData = atob(base64Audio);
      const arrayBuffer = new ArrayBuffer(audioData.length);
      const view = new Uint8Array(arrayBuffer);
      for (let i = 0; i < audioData.length; i++) {
        view[i] = audioData.charCodeAt(i);
      }

      // Gemini returns raw PCM
      const dataInt16 = new Int16Array(arrayBuffer);
      const buffer = audioContext.createBuffer(1, dataInt16.length, 24000);
      const channelData = buffer.getChannelData(0);
      for (let i = 0; i < dataInt16.length; i++) {
        channelData[i] = dataInt16[i] / 32768.0;
      }

      const source = audioContext.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContext.destination);
      source.start();
    }
  } catch (error) {
    console.error("TTS failed", error);
  }
};

import React, { useState, useEffect } from 'react';
import { Problem, Subject, UserStats } from '../types';
import { getAIHint, speakText } from '../services/geminiService';
import { SUBJECT_INFO } from '../constants';
import confetti from 'canvas-confetti';

interface LessonViewProps {
  problem: Problem;
  onFinish: (earnedPoints: number, heartsLost: number) => void;
  onExit: () => void;
}

const LessonView: React.FC<LessonViewProps> = ({ problem, onFinish, onExit }) => {
  const [currentStepIndex, setCurrentStepIndex] = useState(0);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);
  const [hint, setHint] = useState<string | null>(null);
  const [isLoadingHint, setIsLoadingHint] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [heartsUsed, setHeartsUsed] = useState(0);
  const [showExplanation, setShowExplanation] = useState(false);
  const [shake, setShake] = useState(false);

  const currentStep = problem.steps[currentStepIndex];
  const progress = ((currentStepIndex) / problem.steps.length) * 100;

  const handleOptionClick = (option: string) => {
    if (isCorrect) return;
    setSelectedOption(option);
    const correct = option === currentStep.correctAnswer;
    setIsCorrect(correct);

    if (correct) {
      setShowExplanation(true);
      if (currentStepIndex === problem.steps.length - 1) {
        confetti({
          particleCount: 150,
          spread: 70,
          origin: { y: 0.6 }
        });
      }
    } else {
      setShake(true);
      setTimeout(() => setShake(false), 500);
    }
  };

  const nextStep = () => {
    if (currentStepIndex < problem.steps.length - 1) {
      setCurrentStepIndex(prev => prev + 1);
      setSelectedOption(null);
      setIsCorrect(null);
      setHint(null);
      setShowExplanation(false);
    } else {
      onFinish(100, heartsUsed);
    }
  };

  const handleGetHint = async () => {
    if (isLoadingHint) return;
    setIsLoadingHint(true);
    setHeartsUsed(prev => prev + 1);
    try {
      const response = await getAIHint(problem.title, currentStep.question, problem.subject);
      setHint(response);
      await speakText(response);
    } catch (error) {
      setHint("Попробуй подумать еще немного, у тебя получится!");
    } finally {
      setIsLoadingHint(false);
    }
  };

  const handleSpeakExplanation = async () => {
    if (isSpeaking) return;
    setIsSpeaking(true);
    await speakText(currentStep.explanation);
    setIsSpeaking(false);
  };

  return (
    <div className="max-w-2xl mx-auto p-4 flex flex-col min-h-[calc(100vh-80px)]">
      {/* Progress Bar */}
      <div className="mb-8">
        <div className="flex justify-between items-end mb-2">
          <span className="text-sm font-medium text-slate-500">Урок: {problem.title}</span>
          <span className="text-sm font-bold text-blue-600">{Math.round(progress)}%</span>
        </div>
        <div className="w-full h-3 bg-slate-200 rounded-full overflow-hidden">
          <div 
            className="h-full bg-blue-500 step-transition" 
            style={{ width: `${progress}%` }}
          />
        </div>
      </div>

      {/* Subject Badge */}
      <div className="mb-4">
        <span className={`px-3 py-1 rounded-full text-white text-xs font-bold ${SUBJECT_INFO[problem.subject].color}`}>
          {SUBJECT_INFO[problem.subject].icon} {problem.subject}
        </span>
      </div>

      {/* Step Content */}
      <div className={`bg-white rounded-3xl p-6 shadow-xl shadow-blue-100 border border-blue-50 flex-grow transition-transform ${shake ? 'animate-shake' : ''}`}>
        <h2 className="text-xl font-bold text-slate-800 mb-6">{currentStep.question}</h2>

        <div className="space-y-3 mb-8">
          {currentStep.options.map((option, idx) => {
            let stateClass = "border-slate-200 hover:border-blue-400 bg-white";
            if (selectedOption === option) {
              stateClass = isCorrect ? "border-green-500 bg-green-50 text-green-700 shadow-sm" : "border-red-500 bg-red-50 text-red-700";
            }

            return (
              <button
                key={idx}
                disabled={isCorrect === true}
                onClick={() => handleOptionClick(option)}
                className={`w-full text-left p-4 rounded-2xl border-2 font-medium transition-all ${stateClass}`}
              >
                <div className="flex justify-between items-center">
                  <span>{option}</span>
                  {selectedOption === option && (
                    <span>{isCorrect ? '✅' : '❌'}</span>
                  )}
                </div>
              </button>
            );
          })}
        </div>

        {/* AI Hint Section */}
        {hint && (
          <div className="bg-blue-50 border border-blue-100 rounded-2xl p-4 mb-6 flex gap-3 animate-fade-in items-start">
            <div className="text-2xl mt-1">🤖</div>
            <div className="flex-1">
              <p className="text-blue-800 text-sm italic">"{hint}"</p>
              <button 
                onClick={() => speakText(hint)} 
                className="text-[10px] uppercase tracking-wider font-bold text-blue-500 mt-2 hover:text-blue-700"
              >
                🔊 Прослушать еще раз
              </button>
            </div>
          </div>
        )}

        {showExplanation && (
          <div className="bg-green-50 border border-green-100 rounded-2xl p-4 mb-6">
            <div className="flex justify-between items-start mb-2">
