            </div>
            <p className="text-green-700 text-sm">{currentStep.explanation}</p>
          </div>
        )}
      </div>

      {/* Action Footer */}
      <div className="mt-6 flex flex-col sm:flex-row gap-4 sticky bottom-4">
        {!isCorrect && (
          <button
            onClick={handleGetHint}
            disabled={isLoadingHint}
