export default LessonView;

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import LessonView from './components/LessonView';
import ParentDashboard from './components/ParentDashboard';
import { UserStats, View, Subject, Problem } from './types';
import { INITIAL_ACHIEVEMENTS } from './constants';
import { generateProblem } from './services/geminiService';

const App: React.FC = () => {
  const [view, setView] = useState<View>('dashboard');
  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem('bilimai_stats');
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch (e) {
        console.error("Failed to parse saved stats", e);
      }
    }
    return {
      points: 450,
      hearts: 3,
      level: 4,
      currentStreak: 2,
      solvedCount: 15,
      achievements: INITIAL_ACHIEVEMENTS,
    };
  });
  const [currentProblem, setCurrentProblem] = useState<Problem | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);

  // Save data whenever stats change
  useEffect(() => {
    localStorage.setItem('bilimai_stats', JSON.stringify(stats));
  }, [stats]);

  const startLesson = async (subject: Subject) => {
    if (stats.hearts <= 0) {
      alert("У тебя закончились сердца ❤️! Давай восстановим их на главном экране.");
      return;
    }

    setIsGenerating(true);
    try {
      const problem = await generateProblem(subject);
      setCurrentProblem(problem);
      setView('lesson');
    } catch (error) {
      alert("Ой! Помощнику нужно немного отдохнуть. Проверь интернет или попробуй позже.");
    } finally {
      setIsGenerating(false);
    }
  };

  const refillHearts = () => {
    if (stats.hearts >= 3) {
      alert("Твои сердца и так полны! Вперед, к знаниям!");
      return;
    }
    setStats(prev => ({ ...prev, hearts: 3 }));
  };

  const handleLessonFinish = (earnedPoints: number, heartsLost: number) => {
    setStats(prev => {
      const newPoints = prev.points + earnedPoints;
      const newHearts = Math.max(0, prev.hearts - heartsLost);
      const newLevel = Math.floor(newPoints / 500) + 1;
      const newSolvedCount = prev.solvedCount + 1;

      // Update achievements
      const updatedAchievements = prev.achievements.map(ach => {
        if (ach.id === 'future-nis' && newPoints >= 1000) return { ...ach, unlocked: true };
        if (ach.id === 'step-by-step' && heartsLost === 0) return { ...ach, unlocked: true };
        return ach;
      });

      return {
        ...prev,
        points: newPoints,
        hearts: newHearts,
        level: newLevel,
        solvedCount: newSolvedCount,
        achievements: updatedAchievements
      };
    });
    setView('dashboard');
    setCurrentProblem(null);
  };

  return (
    <div className="min-h-screen pb-10">
      <Header stats={stats} onViewChange={setView} />

      <main className="container mx-auto">
        {isGenerating && (
          <div className="fixed inset-0 z-[60] bg-white/90 flex flex-col items-center justify-center p-10 text-center backdrop-blur-sm">
            <div className="w-24 h-24 mb-6 relative">
               <div className="absolute inset-0 border-4 border-blue-100 rounded-full"></div>
               <div className="absolute inset-0 border-4 border-blue-600 rounded-full border-t-transparent animate-spin"></div>
               <div className="absolute inset-0 flex items-center justify-center text-4xl">🤖</div>
            </div>
            <h2 className="text-2xl font-bold text-slate-800 mb-2">BilimAI готовит квест...</h2>
            <p className="text-slate-500 max-w-xs">Создаем уникальную задачу специально для твоего уровня сложности.</p>
          </div>
        )}

        {view === 'dashboard' && (
          <>
            <Dashboard stats={stats} onStartLesson={startLesson} />
            {stats.hearts < 3 && (
              <div className="max-w-4xl mx-auto px-6 mt-4">
                <button 
                  onClick={refillHearts}
                  className="w-full bg-red-100 border-2 border-red-200 text-red-600 font-bold py-4 rounded-3xl hover:bg-red-200 transition-colors flex items-center justify-center gap-3"
                >
                  <span className="text-xl">⚡</span>
                  Восстановить сердца ❤️❤️❤️
                </button>
              </div>
            )}
          </>
        )}

        {view === 'lesson' && currentProblem && (
          <LessonView 
            problem={currentProblem} 
            onFinish={handleLessonFinish}
            onExit={() => {
              setView('dashboard');
              setCurrentProblem(null);
            }}
          />
        )}

        {view === 'parent' && (
          <ParentDashboard stats={stats} />
        )}
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { Subject, Problem } from '../types';

// В Vite для VS Code используется import.meta.env, в системе промптов - process.env
const API_KEY = (import.meta as any).env?.VITE_API_KEY || (process as any).env?.API_KEY || '';

const ai = new GoogleGenAI({ apiKey: API_KEY });

export const generateProblem = async (subject: Subject): Promise<Problem> => {
  if (!API_KEY) {
    throw new Error("API Key is missing. Please check your .env file or environment variables.");
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate a specialized multi-step educational problem for children (9-14) preparing for NIS/BIL exams in ${subject}. 
    The problem must have 3-4 sequential steps. Each step must build on the previous one.
    Format the response as a JSON object matching the Problem interface.
    The language must be Russian. Friendly and clear.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING },
          subject: { type: Type.STRING },
          difficulty: { type: Type.STRING },
          steps: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                question: { type: Type.STRING },
                options: { type: Type.ARRAY, items: { type: Type.STRING } },
                correctAnswer: { type: Type.STRING },
                explanation: { type: Type.STRING }
              },
              required: ["id", "question", "options", "correctAnswer", "explanation"]
            }
          }
        },
        required: ["id", "title", "subject", "difficulty", "steps"]
      }
    }
  });

  try {
    return JSON.parse(response.text);
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw e;
  }
};

export const getAIHint = async (problemTitle: string, currentStepText: string, subject: Subject): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `You are BilimAI, a friendly mentor. The student is solving a problem: "${problemTitle}". 
    They are stuck on this step: "${currentStepText}".
    Subject: ${subject}.
    CRITICAL RULE: DO NOT GIVE THE ANSWER.
    Instead, give a short, encouraging hint (in Russian) that explains the APPROACH or logic they should use. 
    Maximum 2-3 sentences. Use friendly, kid-appropriate language.`,
    config: {
      temperature: 0.7,
      topP: 0.9
    }
  });

  return response.text.trim();
};

export const speakText = async (text: string): Promise<void> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Скажи по-доброму: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const audioData = atob(base64Audio);
      const arrayBuffer = new ArrayBuffer(audioData.length);
      const view = new Uint8Array(arrayBuffer);
      for (let i = 0; i < audioData.length; i++) {
        view[i] = audioData.charCodeAt(i);
      }

      const dataInt16 = new Int16Array(arrayBuffer);
      const buffer = audioContext.createBuffer(1, dataInt16.length, 24000);
      const channelData = buffer.getChannelData(0);
      for (let i = 0; i < dataInt16.length; i++) {
        channelData[i] = dataInt16[i] / 32768.0;
      }

      const source = audioContext.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContext.destination);
      source.start();
    }
  } catch (error) {
    console.error("TTS failed", error);
  }
};

