import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import LessonView from './components/LessonView';
import ParentDashboard from './components/ParentDashboard';
import AuthView from './components/AuthView';
import ProfileView from './components/ProfileView';
import { UserStats, View, Subject, Problem, Language } from './types';
import { INITIAL_ACHIEVEMENTS, TRANSLATIONS } from './constants';
import { generateProblem } from './services/geminiService';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem('bilimai_lang') as Language) || 'ru';
  });

  const [view, setView] = useState<View>('auth');
  const [stats, setStats] = useState<UserStats | null>(() => {
    const saved = localStorage.getItem('bilimai_user');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        // Ensure all achievements are present (for updates)
        const updatedAchievements = INITIAL_ACHIEVEMENTS.map(initial => {
          const existing = parsed.achievements?.find((a: any) => a.id === initial.id);
          return existing ? { ...initial, unlocked: existing.unlocked } : initial;
        });
        return { ...parsed, achievements: updatedAchievements };
      } catch (e) { return null; }
    }
    return null;
  });

  const [currentProblem, setCurrentProblem] = useState<Problem | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);

  useEffect(() => {
    if (stats) {
      localStorage.setItem('bilimai_user', JSON.stringify(stats));
      if (view === 'auth') setView('dashboard');
    }
  }, [stats]);

  useEffect(() => {
    localStorage.setItem('bilimai_lang', lang);
  }, [lang]);

  const handleRegister = (name: string) => {
    const avatars = ['🦊', '🐱', '🐼', '🐨', '🦁', '🦉'];
    const randomAvatar = avatars[Math.floor(Math.random() * avatars.length)];
    setStats({
      name,
      points: 0,
      hearts: 3,
      level: 1,
      currentStreak: 0,
      solvedCount: 0,
      avatar: randomAvatar,
      achievements: INITIAL_ACHIEVEMENTS,
