import { GoogleGenAI, Type, Modality } from "@google/genai";
import { Subject, Problem, Language } from '../types';

// Use process.env.API_KEY exclusively as per guidelines
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateProblem = async (subject: Subject, lang: Language): Promise<Problem> => {
  const languageName = lang === 'ru' ? 'Russian' : 'Kazakh';

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate a specialized multi-step educational problem for children (9-14) preparing for NIS/BIL exams in ${subject}. 
    The problem must have 3-4 sequential steps. Each step must build on the previous one.
    Format the response as a JSON object matching the Problem interface.
    The language must be ${languageName}. Friendly and clear.
    If Kazakh language is used, ensure correct grammar and educational terminology for Kazakhstan schools.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING },
          subject: { type: Type.STRING },
          difficulty: { type: Type.STRING },
          steps: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                question: { type: Type.STRING },
                options: { type: Type.ARRAY, items: { type: Type.STRING } },
                correctAnswer: { type: Type.STRING },
                explanation: { type: Type.STRING }
              },
              required: ["id", "question", "options", "correctAnswer", "explanation"]
            }
          }
        },
        required: ["id", "title", "subject", "difficulty", "steps"]
      }
    }
  });

  try {
    return JSON.parse(response.text);
  } catch (e) {
    throw new Error("Failed to parse AI response");
  }
};

export const getAIHint = async (problemTitle: string, currentStepText: string, subject: Subject, lang: Language): Promise<string> => {
  const languageName = lang === 'ru' ? 'Russian' : 'Kazakh';
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `You are BilimAI, a friendly mentor. The student is solving a problem: "${problemTitle}". 
    They are stuck on this step: "${currentStepText}".
    Subject: ${subject}. Language: ${languageName}.
    CRITICAL RULE: DO NOT GIVE THE ANSWER.
    Give a short, encouraging hint in ${languageName} explaining the logic.`,
    config: { temperature: 0.7 }
  });
  return response.text.trim();
};

// Standard base64 decoding helper as per guidelines
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// Standard PCM audio decoding helper as per guidelines
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const speakText = async (text: string): Promise<void> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            // Kore is used for clear educational instruction
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });
    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const outputAudioContext = new (window.AudioContext ||
        (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const audioBuffer = await decodeAudioData(
        decode(base64Audio),
        outputAudioContext,
        24000,
        1,
      );

      const source = outputAudioContext.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(outputAudioContext.destination);
      source.start();
    }
  } catch (e) {
    console.error("Speech synthesis failed:", e);
  }
};

import React, { useState } from 'react';
import { Problem, Language } from '../types';
import { getAIHint, speakText } from '../services/geminiService';
import { SUBJECT_INFO, TRANSLATIONS } from '../constants';
import confetti from 'canvas-confetti';

interface LessonViewProps {
  problem: Problem;
  lang: Language;
  onFinish: (earnedPoints: number, heartsLost: number) => void;
  onExit: () => void;
}

const LessonView: React.FC<LessonViewProps> = ({ problem, lang, onFinish, onExit }) => {
  const [currentStepIndex, setCurrentStepIndex] = useState(0);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);
  const [hint, setHint] = useState<string | null>(null);
  const [isLoadingHint, setIsLoadingHint] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [heartsUsed, setHeartsUsed] = useState(0);
  const [showExplanation, setShowExplanation] = useState(false);
  const [shake, setShake] = useState(false);

  const t = TRANSLATIONS[lang];
  const currentStep = problem.steps[currentStepIndex];
  const progress = ((currentStepIndex + 1) / problem.steps.length) * 100;

  const handleOptionClick = (option: string) => {
    if (isCorrect === true) return;
    setSelectedOption(option);
    const correct = option === currentStep.correctAnswer;
    setIsCorrect(correct);

    if (correct) {
      setShowExplanation(true);
      if (currentStepIndex === problem.steps.length - 1) {
        confetti({
          particleCount: 150,
          spread: 70,
          origin: { y: 0.6 }
        });
      }
    } else {
      setShake(true);
      setTimeout(() => setShake(false), 500);
    }
  };

  const nextStep = () => {
    if (currentStepIndex < problem.steps.length - 1) {
      setCurrentStepIndex(prev => prev + 1);
      setSelectedOption(null);
      setIsCorrect(null);
      setHint(null);
      setShowExplanation(false);
    } else {
      onFinish(100, heartsUsed);
    }
  };

  const handleGetHint = async () => {
    if (isLoadingHint) return;
    setIsLoadingHint(true);
    setHeartsUsed(prev => prev + 1);
    try {
      const response = await getAIHint(problem.title, currentStep.question, problem.subject, lang);
      setHint(response);
      await speakText(response);
    } catch (error) {
      setHint(lang === 'ru' ? "Попробуй подумать еще немного!" : "Тағы біраз ойланып көр!");
    } finally {
      setIsLoadingHint(false);
    }
  };

  const handleSpeakExplanation = async () => {
    if (isSpeaking) return;
    setIsSpeaking(true);
    await speakText(currentStep.explanation);
    setIsSpeaking(false);
  };

  return (
    <div className="max-w-2xl mx-auto p-4 flex flex-col min-h-screen pb-24 animate-fade-in">
      {/* Progress Bar */}
      <div className="mb-8">
        <div className="flex justify-between items-end mb-2">
          <span className="text-sm font-medium text-slate-500">
            {lang === 'ru' ? 'Урок' : 'Сабақ'}: {problem.title}
          </span>
          <span className="text-sm font-bold text-blue-600">{Math.round(progress)}%</span>
        </div>
        <div className="w-full h-3 bg-slate-200 rounded-full overflow-hidden shadow-inner">
          <div 
            className="h-full bg-blue-500 step-transition shadow-[0_0_10px_rgba(59,130,246,0.5)]" 
            style={{ width: `${progress}%` }}
          />
        </div>
      </div>

      {/* Subject Badge */}
      <div className="mb-4">
        <span className={`px-4 py-1.5 rounded-full text-white text-xs font-bold shadow-md ${SUBJECT_INFO[problem.subject].color}`}>
          {SUBJECT_INFO[problem.subject].icon} {lang === 'kk' ? SUBJECT_INFO[problem.subject].kk : problem.subject}
        </span>
      </div>

      {/* Step Content */}
      <div className={`bg-white rounded-[32px] p-6 sm:p-8 shadow-xl shadow-blue-100/50 border border-blue-50 flex-grow transition-all duration-300 ${shake ? 'animate-shake' : ''}`}>
        <h2 className="text-xl sm:text-2xl font-bold text-slate-800 mb-8 leading-tight">
          {currentStep.question}
        </h2>

        <div className="grid grid-cols-1 gap-4 mb-8">
          {currentStep.options.map((option, idx) => {
            const isSelected = selectedOption === option;
            let stateClass = "border-slate-200 hover:border-blue-300 bg-white text-slate-700 shadow-sm";

            if (isSelected) {
              stateClass = isCorrect 
                ? "border-green-500 bg-green-50 text-green-700 shadow-md ring-2 ring-green-200" 
                : "border-red-500 bg-red-50 text-red-700 shadow-md ring-2 ring-red-200";
            }

            return (
              <button
                key={idx}
                disabled={isCorrect === true}
                onClick={() => handleOptionClick(option)}
                className={`group relative w-full text-left p-5 rounded-2xl border-2 font-semibold transition-all duration-200 active:scale-[0.98] ${stateClass}`}
              >
                <div className="flex justify-between items-center gap-4">
                  <span className="flex-1">{option}</span>
                  {isSelected && (
                    <span className="text-xl flex-shrink-0">
                      {isCorrect ? '✨' : '⚠️'}
                    </span>
                  )}
                </div>
              </button>
            );
          })}
        </div>

        {/* AI Hint Section */}
        {hint && (
          <div className="bg-blue-50 border border-blue-100 rounded-2xl p-5 mb-6 flex gap-4 animate-fade-in items-start shadow-sm">
            <div className="text-3xl filter drop-shadow-sm">🤖</div>
            <div className="flex-1">
              <p className="text-blue-900 text-sm leading-relaxed font-medium italic">"{hint}"</p>
              <button 
                onClick={() => speakText(hint)} 
                className="inline-flex items-center gap-1.5 text-[11px] uppercase tracking-wider font-bold text-blue-500 mt-3 hover:text-blue-700 transition-colors"
              >
                <span>🔊</span> {lang === 'ru' ? 'Слушать' : 'Тыңдау'}
              </button>
            </div>
          </div>
        )}

        {showExplanation && (
          <div className="bg-green-50 border border-green-100 rounded-2xl p-5 mb-6 animate-fade-in shadow-sm">
            <div className="flex justify-between items-center mb-3">
              <h4 className="font-bold text-green-800 text-sm flex items-center gap-2">
                <span>🌟</span> {t.explanation}:
              </h4>
              <button 
                onClick={handleSpeakExplanation} 
                className="w-8 h-8 flex items-center justify-center bg-white rounded-full shadow-sm hover:scale-110 transition-transform border border-green-200"
              >
                🔊
              </button>
            </div>
            <p className="text-green-700 text-sm leading-relaxed">{currentStep.explanation}</p>
          </div>
        )}
      </div>

      {/* Action Footer */}
      <div className="mt-8 flex flex-col gap-4">
        {!isCorrect && (
          <button
            onClick={handleGetHint}
            disabled={isLoadingHint}
            className="w-full bg-white border-2 border-blue-100 text-blue-600 font-bold py-4 rounded-2xl shadow-lg hover:shadow-xl hover:bg-blue-50 transition-all flex items-center justify-center gap-3 active:scale-95"
          >
            {isLoadingHint ? (
              <div className="w-5 h-5 border-3 border-blue-600 border-t-transparent animate-spin rounded-full"></div>
            ) : (
              <>
                <span className="text-2xl">🤖</span>
                {t.hint} (-1 ❤️)
              </>
            )}
          </button>
        )}

        {isCorrect && (
          <button
            onClick={nextStep}
            className="w-full bg-blue-600 text-white font-bold py-5 rounded-2xl shadow-xl shadow-blue-200 hover:bg-blue-700 hover:-translate-y-1 transition-all flex items-center justify-center gap-3 active:scale-95"
          >
            <span className="text-lg">
              {currentStepIndex < problem.steps.length - 1 ? t.next : t.finish}
            </span>
            <span className="text-2xl">🚀</span>
          </button>
        )}

        <button 
          onClick={onExit}
          className="py-2 text-slate-400 text-sm font-medium hover:text-red-400 transition-colors text-center"
        >
          {lang === 'ru' ? 'Прервать обучение' : 'Оқуды тоқтату'}
        </button>
      </div>
    </div>
  );
};

export default LessonView;

