              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="Alisher"
                className="w-full p-4 rounded-2xl border-2 border-slate-100 focus:border-blue-500 outline-none transition-all"
                required={!isLogin}
              />
            </div>
          )}

          <div>
            <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2 ml-1">{t.email}</label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="example@mail.com"
              className="w-full p-4 rounded-2xl border-2 border-slate-100 focus:border-blue-500 outline-none transition-all"
              required
            />
          </div>

          <div>
            <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2 ml-1">{t.password}</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••"
              className="w-full p-4 rounded-2xl border-2 border-slate-100 focus:border-blue-500 outline-none transition-all"
              required
            />
          </div>

          <button
            type="submit"
            className="w-full bg-blue-600 text-white font-bold py-5 rounded-2xl shadow-lg hover:bg-blue-700 hover:-translate-y-1 active:scale-95 transition-all mt-4"
          >
            {isLogin ? t.login : t.letsGo}
          </button>
        </form>

        <button
          onClick={() => setIsLogin(!isLogin)}
          className="w-full text-center mt-6 text-sm font-bold text-blue-600 hover:text-blue-800 transition-colors"
        >
          {isLogin ? t.noAccount : t.haveAccount}
        </button>
      </div>
    </div>
  );
};

export default AuthView;

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import LessonView from './components/LessonView';
import ParentDashboard from './components/ParentDashboard';
import AuthView from './components/AuthView';
import ProfileView from './components/ProfileView';
import { UserStats, View, Subject, Problem, Language } from './types';
import { INITIAL_ACHIEVEMENTS, TRANSLATIONS } from './constants';
import { generateProblem } from './services/geminiService';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem('bilimai_lang') as Language) || 'ru';
  });

  const [view, setView] = useState<View>('auth');
  const [currentUserEmail, setCurrentUserEmail] = useState<string | null>(() => {
    return localStorage.getItem('bilimai_active_user');
  });

  const [stats, setStats] = useState<UserStats | null>(null);

  // Load user data whenever currentEmail changes
  useEffect(() => {
    if (currentUserEmail) {
      const allUsers = JSON.parse(localStorage.getItem('bilimai_users') || '{}');
      const userData = allUsers[currentUserEmail];
      if (userData) {
        // Ensure achievements are up to date with initial definitions
        const updatedAchievements = INITIAL_ACHIEVEMENTS.map(initial => {
          const existing = userData.achievements?.find((a: any) => a.id === initial.id);
          return existing ? { ...initial, unlocked: existing.unlocked } : initial;
        });
        setStats({ ...userData, achievements: updatedAchievements });
        setView('dashboard');
      }
    }
  }, [currentUserEmail]);

  // Persist user data to local "database"
  useEffect(() => {
    if (stats) {
      const allUsers = JSON.parse(localStorage.getItem('bilimai_users') || '{}');
      allUsers[stats.email] = stats;
      localStorage.setItem('bilimai_users', JSON.stringify(allUsers));
    }
  }, [stats]);

  useEffect(() => {
    localStorage.setItem('bilimai_lang', lang);
  }, [lang]);

  const handleAuth = (email: string, name: string, isNew: boolean) => {
    const allUsers = JSON.parse(localStorage.getItem('bilimai_users') || '{}');

    if (isNew) {
      const avatars = ['🦊', '🐱', '🐼', '🐨', '🦁', '🦉'];
      const randomAvatar = avatars[Math.floor(Math.random() * avatars.length)];
      const newUser: UserStats = {
        email,
        name,
        points: 0,
        hearts: 3,
        level: 1,
        currentStreak: 0,
        solvedCount: 0,
        avatar: randomAvatar,
        achievements: INITIAL_ACHIEVEMENTS,
      };
      allUsers[email] = newUser;
      localStorage.setItem('bilimai_users', JSON.stringify(allUsers));
      setCurrentUserEmail(email);
      localStorage.setItem('bilimai_active_user', email);
    } else {
      if (allUsers[email]) {
        setCurrentUserEmail(email);
        localStorage.setItem('bilimai_active_user', email);
      } else {
        alert(lang === 'ru' ? 'Пользователь не найден!' : 'Пайдаланушы табылмады!');
      }
    }
  };

  const handleLogout = () => {
    if (window.confirm(lang === 'ru' ? 'Точно выйти?' : 'Шынымен шығасыз ба?')) {
      localStorage.removeItem('bilimai_active_user');
      setCurrentUserEmail(null);
      setStats(null);
      setView('auth');
    }
  };

  const checkAchievements = (newStats: UserStats): any[] => {
    return newStats.achievements.map(ach => {
      if (ach.unlocked) return ach;
      let isUnlocked = false;
      if (ach.type === 'points' && newStats.points >= ach.requirement) isUnlocked = true;
      if (ach.type === 'solved' && newStats.solvedCount >= ach.requirement) isUnlocked = true;
      if (ach.type === 'streak' && newStats.currentStreak >= ach.requirement) isUnlocked = true;
      return isUnlocked ? { ...ach, unlocked: true } : ach;
    });
  };

  const [currentProblem, setCurrentProblem] = useState<Problem | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);

  const startLesson = async (subject: Subject) => {
    if (!stats || stats.hearts <= 0) {
      alert(lang === 'ru' ? "У тебя закончились сердца ❤️!" : "Жүрегің таусылды ❤️!");
      return;
    }
    setIsGenerating(true);
    try {
      const problem = await generateProblem(subject, lang);
      setCurrentProblem(problem);
      setView('lesson');
    } catch (e) {
      alert("AI offline");
    } finally { setIsGenerating(false); }
  };

  const handleLessonFinish = (earnedPoints: number, heartsLost: number) => {
    if (!stats) return;
    setStats(prev => {
      if (!prev) return null;
      const newPoints = prev.points + earnedPoints;
      const newHearts = Math.max(0, prev.hearts - heartsLost);
      const newSolvedCount = prev.solvedCount + 1;
      const newLevel = Math.floor(newPoints / 500) + 1;

      let tempStats = { ...prev, points: newPoints, hearts: newHearts, solvedCount: newSolvedCount, level: newLevel };
      tempStats.achievements = checkAchievements(tempStats);
      return tempStats;
    });
    setView('dashboard');
    setCurrentProblem(null);
  };

  const t = TRANSLATIONS[lang];

  return (
    <div className="min-h-screen pb-10 flex flex-col">
      {stats && <Header stats={stats} lang={lang} onLanguageChange={setLang} onViewChange={setView} />}

      <main className="container mx-auto flex-grow px-4">
        {isGenerating && (
          <div className="fixed inset-0 z-[60] bg-white/95 flex flex-col items-center justify-center p-10 text-center backdrop-blur-md animate-fade-in">
            <div className="w-24 h-24 mb-6 relative">
               <div className="absolute inset-0 border-4 border-blue-600 rounded-full border-t-transparent animate-spin"></div>
               <div className="absolute inset-0 flex items-center justify-center text-5xl animate-bounce">🤖</div>
            </div>
            <h2 className="text-3xl font-bold text-slate-800 mb-3">{t.loading}</h2>
          </div>
        )}

        {!stats && view === 'auth' && <AuthView onAuth={handleAuth} lang={lang} />}

        {stats && view === 'dashboard' && (
          <Dashboard stats={stats} lang={lang} onStartLesson={startLesson} onViewChange={setView} />
        )}

        {stats && view === 'profile' && (
          <ProfileView stats={stats} lang={lang} onLogout={handleLogout} />
        )}

        {stats && view === 'lesson' && currentProblem && (
          <LessonView 
            problem={currentProblem} 
            lang={lang}
            onFinish={handleLessonFinish}
            onExit={() => setView('dashboard')}
          />
        )}

        {stats && view === 'parent' && <ParentDashboard stats={stats} lang={lang} />}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Problem, Language } from '../types';
import { getAIHint, speakText } from '../services/geminiService';
import { SUBJECT_INFO, TRANSLATIONS } from '../constants';
import confetti from 'canvas-confetti';

interface LessonViewProps {
  problem: Problem;
  lang: Language;
  userHearts: number;
  onFinish: (earnedPoints: number, heartsLost: number) => void;
  onExit: () => void;
}

const LessonView: React.FC<LessonViewProps> = ({ problem, lang, userHearts, onFinish, onExit }) => {
  const [currentStepIndex, setCurrentStepIndex] = useState(0);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);
  const [hint, setHint] = useState<string | null>(null);
  const [isLoadingHint, setIsLoadingHint] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [heartsUsed, setHeartsUsed] = useState(0);
  const [totalMistakes, setTotalMistakes] = useState(0);
  const [showExplanation, setShowExplanation] = useState(false);
  const [shake, setShake] = useState(false);
  const [showPenalty, setShowPenalty] = useState(false);

  const t = TRANSLATIONS[lang];
  const currentStep = problem.steps[currentStepIndex];
  const progress = ((currentStepIndex + 1) / problem.steps.length) * 100;

  const handleOptionClick = (option: string) => {
    if (isCorrect === true || selectedOption === option) return;

    setSelectedOption(option);
    const correct = option === currentStep.correctAnswer;
    setIsCorrect(correct);

    if (correct) {
      setShowExplanation(true);
      if (currentStepIndex === problem.steps.length - 1) {
        confetti({
          particleCount: 150,
          spread: 70,
          origin: { y: 0.6 }
        });
      }
    } else {
      setShake(true);
      setTotalMistakes(prev => prev + 1);
      setShowPenalty(true);
      setTimeout(() => setShowPenalty(false), 1500);
      setTimeout(() => setShake(false), 500);
    }
  };

  const nextStep = () => {
    if (currentStepIndex < problem.steps.length - 1) {
      setCurrentStepIndex(prev => prev + 1);
      setSelectedOption(null);
      setIsCorrect(null);
      setHint(null);
      setShowExplanation(false);
    } else {
      // Итоговые баллы: База 100 - (количество ошибок * 10)
      const earnedPoints = Math.max(0, 100 - (totalMistakes * 10));
      onFinish(earnedPoints, heartsUsed);
    }
  };

  const handleGetHint = async () => {
    if (isLoadingHint) return;
    if (userHearts - heartsUsed <= 0) {
      alert(t.noHeartsHint);
      return;
    }

    setIsLoadingHint(true);
    setHeartsUsed(prev => prev + 1);
    try {
      const response = await getAIHint(problem.title, currentStep.question, problem.subject, lang);
      setHint(response);
      await speakText(response);
    } catch (error) {
      setHint(lang === 'ru' ? "Попробуй подумать еще немного!" : "Тағы біраз ойланып көр!");
    } finally {
      setIsLoadingHint(false);
    }
  };

  const handleSpeakExplanation = async () => {
    if (isSpeaking) return;
    setIsSpeaking(true);
    await speakText(currentStep.explanation);
    setIsSpeaking(false);
  };

  return (
    <div className="max-w-2xl mx-auto p-4 flex flex-col min-h-screen pb-24 animate-fade-in relative">
      {/* Penalty floating indicator */}
      {showPenalty && (
        <div className="fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-[100] bg-red-500 text-white px-6 py-3 rounded-full font-bold shadow-2xl animate-bounce">
          {t.wrongAnswer}
        </div>
      )}

      {/* Progress Bar */}
      <div className="mb-8">
        <div className="flex justify-between items-end mb-2">
          <span className="text-sm font-medium text-slate-500">
            {t.lesson}: {problem.title}
          </span>
          <span className="text-sm font-bold text-blue-600">{Math.round(progress)}%</span>
        </div>
        <div className="w-full h-3 bg-slate-200 rounded-full overflow-hidden shadow-inner">
          <div 
            className="h-full bg-blue-500 step-transition shadow-[0_0_10px_rgba(59,130,246,0.5)]" 
            style={{ width: `${progress}%` }}
          />
        </div>
      </div>

      {/* Subject Badge */}
      <div className="mb-4 flex justify-between items-center">
        <span className={`px-4 py-1.5 rounded-full text-white text-xs font-bold shadow-md ${SUBJECT_INFO[problem.subject].color}`}>
          {SUBJECT_INFO[problem.subject].icon} {lang === 'kk' ? SUBJECT_INFO[problem.subject].kk : problem.subject}
        </span>
        <div className="flex items-center gap-2">
          <span className="text-xs font-bold text-slate-400">ШТРАФ:</span>
          <span className="text-sm font-bold text-red-500">-{totalMistakes * 10} ⭐</span>
        </div>
      </div>

      {/* Step Content */}
      <div className={`bg-white rounded-[32px] p-6 sm:p-8 shadow-xl shadow-blue-100/50 border border-blue-50 flex-grow transition-all duration-300 ${shake ? 'animate-shake' : ''}`}>
        <h2 className="text-xl sm:text-2xl font-bold text-slate-800 mb-8 leading-tight">
          {currentStep.question}
        </h2>

        <div className="grid grid-cols-1 gap-4 mb-8">
          {currentStep.options.map((option, idx) => {
            const isSelected = selectedOption === option;
            let stateClass = "border-slate-200 hover:border-blue-300 bg-white text-slate-700 shadow-sm";

            if (isSelected) {
              stateClass = isCorrect 
                ? "border-green-500 bg-green-50 text-green-700 shadow-md ring-2 ring-green-200" 
                : "border-red-500 bg-red-50 text-red-700 shadow-md ring-2 ring-red-200";
            }

            return (
              <button
                key={idx}
                disabled={isCorrect === true}
                onClick={() => handleOptionClick(option)}
                className={`group relative w-full text-left p-5 rounded-2xl border-2 font-semibold transition-all duration-200 active:scale-[0.98] ${stateClass}`}
              >
                <div className="flex justify-between items-center gap-4">
                  <span className="flex-1">{option}</span>
                  {isSelected && (
                    <span className="text-xl flex-shrink-0">
                      {isCorrect ? '✨' : '⚠️'}
                    </span>
                  )}
                </div>
              </button>
            );
          })}
        </div>

        {/* AI Hint Section */}
        {hint && (
          <div className="bg-blue-50 border border-blue-100 rounded-2xl p-5 mb-6 flex gap-4 animate-fade-in items-start shadow-sm">
            <div className="text-3xl filter drop-shadow-sm">🤖</div>
            <div className="flex-1">
              <p className="text-blue-900 text-sm leading-relaxed font-medium italic">"{hint}"</p>
              <button 
                onClick={() => speakText(hint)} 
                className="inline-flex items-center gap-1.5 text-[11px] uppercase tracking-wider font-bold text-blue-500 mt-3 hover:text-blue-700 transition-colors"
              >
                <span>🔊</span> {t.listen}
              </button>
            </div>
          </div>
        )}

        {showExplanation && (
          <div className="bg-green-50 border border-green-100 rounded-2xl p-5 mb-6 animate-fade-in shadow-sm">
            <div className="flex justify-between items-center mb-3">
              <h4 className="font-bold text-green-800 text-sm flex items-center gap-2">
                <span>🌟</span> {t.explanation}:
              </h4>
              <button 
                onClick={handleSpeakExplanation} 
                className="w-8 h-8 flex items-center justify-center bg-white rounded-full shadow-sm hover:scale-110 transition-transform border border-green-200"
              >
                🔊
              </button>
            </div>
            <p className="text-green-700 text-sm leading-relaxed">{currentStep.explanation}</p>
          </div>
        )}
      </div>

      {/* Action Footer */}
      <div className="mt-8 flex flex-col gap-4">
        {!isCorrect && (
          <button
            onClick={handleGetHint}
            disabled={isLoadingHint || userHearts - heartsUsed <= 0}
            className="w-full bg-white border-2 border-blue-100 text-blue-600 font-bold py-4 rounded-2xl shadow-lg hover:shadow-xl hover:bg-blue-50 transition-all flex items-center justify-center gap-3 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isLoadingHint ? (
              <div className="w-5 h-5 border-3 border-blue-600 border-t-transparent animate-spin rounded-full"></div>
            ) : (
              <>
                <span className="text-2xl">🤖</span>
                {t.hint} (-1 ❤️)
              </>
            )}
          </button>
        )}

        {isCorrect && (
          <button
            onClick={nextStep}
            className="w-full bg-blue-600 text-white font-bold py-5 rounded-2xl shadow-xl shadow-blue-200 hover:bg-blue-700 hover:-translate-y-1 transition-all flex items-center justify-center gap-3 active:scale-95"
          >
            <span className="text-lg">
              {currentStepIndex < problem.steps.length - 1 ? t.next : t.finish}
            </span>
            <span className="text-2xl">🚀</span>
          </button>
        )}

        <button 
          onClick={onExit}
          className="py-2 text-slate-400 text-sm font-medium hover:text-red-400 transition-colors text-center"
        >
          {t.stopLearning}
        </button>
      </div>
    </div>
  );
};

