import { GoogleGenAI, Type, Modality } from "@google/genai";
import { Subject, Problem, Language } from '../types';

// Use process.env.API_KEY exclusively as per guidelines
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateProblem = async (subject: Subject, lang: Language): Promise<Problem> => {
  const languageName = lang === 'ru' ? 'Russian' : 'Kazakh';

  // Mapping subject to English to help the model understand context better regardless of UI language
  const subjectMap: Record<string, string> = {
    'Математика': 'Mathematics',
    'Логика': 'Logic and Reasoning',
    'Чтение': 'Reading Comprehension',
    'Критическое мышление': 'Critical Thinking'
  };
  const englishSubject = subjectMap[subject as string] || subject;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    config: {
      systemInstruction: `You are an expert educator creating exam prep content for NIS (Nazarbayev Intellectual Schools) and BIL (BIL-Inovatsiya Lyceums).
      Your task is to generate educational problems in the ${languageName} language.
      STRICT RULE: Every single string in the JSON output MUST be in ${languageName}. 
      Do not use any other language for title, questions, options, or explanations.`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING },
          subject: { type: Type.STRING },
          difficulty: { type: Type.STRING },
          steps: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                question: { type: Type.STRING },
                options: { type: Type.ARRAY, items: { type: Type.STRING } },
                correctAnswer: { type: Type.STRING },
                explanation: { type: Type.STRING }
              },
              required: ["id", "question", "options", "correctAnswer", "explanation"]
            }
          }
        },
        required: ["id", "title", "subject", "difficulty", "steps"]
      }
    },
    contents: `Generate a specialized multi-step educational problem for children (9-14) preparing for NIS/BIL entrance exams.
    Topic/Subject: ${englishSubject} (labeled as "${subject}" in the output).
    The problem must have 3 sequential steps. Each step must build on the previous logic.
    MANDATORY: Use ONLY the ${languageName} language for all content.
    If Kazakh language is used, ensure professional academic Kazakh (using Cyrillic script).`
  });

  try {
    const data = JSON.parse(response.text);
    // Ensure the subject field matches what the app expects if AI changed it
    data.subject = subject; 
    return data;
  } catch (e) {
    throw new Error("Failed to parse AI response: " + e);
  }
};

export const getAIHint = async (problemTitle: string, currentStepText: string, subject: Subject, lang: Language): Promise<string> => {
  const languageName = lang === 'ru' ? 'Russian' : 'Kazakh';
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    config: {
      systemInstruction: `You are BilimAI, a friendly and encouraging mentor for children. 
      You speak only in ${languageName}.`,
      temperature: 0.7 
    },
    contents: `The student is solving a problem: "${problemTitle}". 
    They are stuck on this step: "${currentStepText}".
    Subject: ${subject}. Language: ${languageName}.
    CRITICAL RULE: DO NOT GIVE THE DIRECT ANSWER.
    Give a short, encouraging hint in ${languageName} explaining the logic to help them find the solution themselves.`
  });
  return response.text.trim();
};

// Standard base64 decoding helper as per guidelines
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// Standard PCM audio decoding helper as per guidelines
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const speakText = async (text: string): Promise<void> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });
    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const outputAudioContext = new (window.AudioContext ||
        (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const audioBuffer = await decodeAudioData(
        decode(base64Audio),
        outputAudioContext,
        24000,
        1,
      );

      const source = outputAudioContext.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(outputAudioContext.destination);
      source.start();
    }
  } catch (e) {
    console.error("Speech synthesis failed:", e);
  }
};

