              </div>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
};

export default ProfileView;

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { Subject, Problem, Language } from '../types';

// Use process.env.API_KEY exclusively as per guidelines
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateProblem = async (subject: Subject, lang: Language): Promise<Problem> => {
  const languageName = lang === 'ru' ? 'Russian' : 'Kazakh';

  // Mapping subject to English and target language to help the model
  const subjectMap: Record<string, {en: string, native: string}> = {
    [Subject.MATH]: { en: 'Mathematics', native: lang === 'kk' ? 'Математика' : 'Математика' },
    [Subject.LOGIC]: { en: 'Logic and Reasoning', native: lang === 'kk' ? 'Логика' : 'Логика' },
    [Subject.READING]: { en: 'Reading Comprehension', native: lang === 'kk' ? 'Оқу сауаттылығы' : 'Чтение' },
    [Subject.CRITICAL]: { en: 'Critical Thinking', native: lang === 'kk' ? 'Сыни ойлау' : 'Критическое мышление' }
  };

  const info = subjectMap[subject] || { en: subject, native: subject };

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    config: {
      systemInstruction: `You are an expert educator for NIS (Nazarbayev Intellectual Schools) and BIL (BIL-Inovatsiya Lyceums).
      STRICT LANGUAGE RULE: Generate all content EXCLUSIVELY in the ${languageName} language.
      - If ${languageName} is Kazakh: Use Academic Kazakh (Cyrillic script). Do not use Russian words.
      - If ${languageName} is Russian: Use Academic Russian.
      - All JSON fields (title, question, options, explanation) must be in ${languageName}.
      - The difficulty levels are: 'Легко', 'Средне', 'Сложно' (keep these keys as they are types in the app, but content must be localized).`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING },
          subject: { type: Type.STRING },
          difficulty: { type: Type.STRING },
          steps: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                question: { type: Type.STRING },
                options: { type: Type.ARRAY, items: { type: Type.STRING } },
                correctAnswer: { type: Type.STRING },
                explanation: { type: Type.STRING }
              },
              required: ["id", "question", "options", "correctAnswer", "explanation"]
            }
          }
        },
        required: ["id", "title", "subject", "difficulty", "steps"]
      }
    },
    contents: `Generate a challenging 3-step educational problem for a student preparing for NIS entrance exams.
    Subject: ${info.en} (${info.native}).
    Target Language: ${languageName}.
    The steps must be logical and sequential. Ensure the explanation clarifies the reasoning in ${languageName}.`
  });

  try {
    const data = JSON.parse(response.text);
    // Ensure internal subject enum value is preserved
    data.subject = subject; 
    return data;
  } catch (e) {
    console.error("AI Response Error:", response.text);
    throw new Error("AI data corruption: " + e);
  }
};

export const getAIHint = async (problemTitle: string, currentStepText: string, subject: Subject, lang: Language): Promise<string> => {
  const languageName = lang === 'ru' ? 'Russian' : 'Kazakh';
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    config: {
      systemInstruction: `You are BilimAI, a supportive mentor. Speak ONLY in ${languageName}. Never use other languages.`,
      temperature: 0.7 
    },
    contents: `The student is stuck on a ${subject} problem: "${problemTitle}". 
    Current step: "${currentStepText}". 
    Give a helpful hint in ${languageName} WITHOUT giving the answer.`
  });
  return response.text.trim();
};

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const speakText = async (text: string): Promise<void> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });
    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const outputAudioContext = new (window.AudioContext ||
        (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const audioBuffer = await decodeAudioData(decode(base64Audio), outputAudioContext, 24000, 1);
      const source = outputAudioContext.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(outputAudioContext.destination);
      source.start();
    }
  } catch (e) {
    console.error("TTS failed:", e);
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import LessonView from './components/LessonView';
import ParentDashboard from './components/ParentDashboard';
import AuthView from './components/AuthView';
import ProfileView from './components/ProfileView';
import { UserStats, View, Subject, Problem, Language } from './types';
import { INITIAL_ACHIEVEMENTS, TRANSLATIONS } from './constants';
import { generateProblem } from './services/geminiService';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem('bilimai_lang') as Language) || 'ru';
  });

  const [view, setView] = useState<View>('auth');
  const [stats, setStats] = useState<UserStats | null>(null);

  // Persistence helpers
  const getUsersFromStorage = (): Record<string, UserStats> => {
    try {
      const data = localStorage.getItem('bilimai_users');
      return data ? JSON.parse(data) : {};
    } catch {
      return {};
    }
  };

  const saveUserToStorage = (user: UserStats) => {
    const allUsers = getUsersFromStorage();
    allUsers[user.email.toLowerCase()] = user;
    localStorage.setItem('bilimai_users', JSON.stringify(allUsers));
  };

  // Load session on mount
  useEffect(() => {
    const activeEmail = localStorage.getItem('bilimai_active_user');
    if (activeEmail) {
      const allUsers = getUsersFromStorage();
      const userData = allUsers[activeEmail.toLowerCase()];
      if (userData) {
        if (!userData.subjectProgress) {
          userData.subjectProgress = {};
          Object.values(Subject).forEach(s => userData.subjectProgress[s] = 0);
        }
        setStats(userData);
        setView('dashboard');
      }
    }
  }, []);

  // Sync current stats to storage whenever they change
  useEffect(() => {
    if (stats) {
      saveUserToStorage(stats);
    }
  }, [stats]);

  useEffect(() => {
    localStorage.setItem('bilimai_lang', lang);
  }, [lang]);

  const handleAuth = (email: string, password: string, name: string, isNew: boolean) => {
    const emailKey = email.toLowerCase().trim();
    const allUsers = getUsersFromStorage();
    const t = TRANSLATIONS[lang];

    if (isNew) {
      if (allUsers[emailKey]) {
        alert(lang === 'ru' ? "Такой email уже зарегистрирован!" : "Бұл email тіркеліп қойған!");
        return;
      }

      const avatars = ['🦊', '🐱', '🐼', '🐨', '🦁', '🦉'];
      const randomAvatar = avatars[Math.floor(Math.random() * avatars.length)];

      const subProg: Record<string, number> = {};
      Object.values(Subject).forEach(s => subProg[s] = 0);

      const newUser: UserStats = {
        email: emailKey,
        password,
        name: name.trim(),
        points: 0,
        hearts: 5,
        level: 1,
        currentStreak: 0,
        solvedCount: 0,
        subjectProgress: subProg,
        avatar: randomAvatar,
        achievements: JSON.parse(JSON.stringify(INITIAL_ACHIEVEMENTS)),
      };

      saveUserToStorage(newUser);
      localStorage.setItem('bilimai_active_user', emailKey);
      setStats(newUser);
      setView('dashboard');
    } else {
      const user = allUsers[emailKey];
      if (user) {
        if (user.password === password) {
          localStorage.setItem('bilimai_active_user', emailKey);
          setStats(user);
          setView('dashboard');
        } else {
          alert(t.wrongPassword);
        }
      } else {
        alert(t.userNotFound);
      }
    }
  };

  const handleLogout = () => {
    const confirmMsg = lang === 'ru' ? 'Вы точно хотите выйти?' : 'Шынымен шыққыңыз келе ме?';
    if (window.confirm(confirmMsg)) {
      localStorage.removeItem('bilimai_active_user');
      setStats(null);
      setView('auth');
    }
  };

  const checkAchievements = (newStats: UserStats): any[] => {
    return newStats.achievements.map(ach => {
      if (ach.unlocked) return ach;
      let isUnlocked = false;
      if (ach.type === 'points' && newStats.points >= ach.requirement) isUnlocked = true;
      if (ach.type === 'solved' && newStats.solvedCount >= ach.requirement) isUnlocked = true;
      if (ach.type === 'streak' && newStats.currentStreak >= ach.requirement) isUnlocked = true;
      return isUnlocked ? { ...ach, unlocked: true } : ach;
    });
  };

  const [currentProblem, setCurrentProblem] = useState<Problem | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);

  const startLesson = async (subject: Subject) => {
    if (!stats || stats.hearts <= 0) {
      alert(lang === 'ru' ? "Восстанови сердца в профиле! ❤️" : "Профильде жүректі толтыр! ❤️");
      return;
    }
    setIsGenerating(true);
    try {
      const problem = await generateProblem(subject, lang);
      setCurrentProblem(problem);
      setView('lesson');
    } catch (e) {
      alert("AI Error: " + e);
    } finally { setIsGenerating(false); }
  };

  const handleLessonFinish = (earnedPoints: number, heartsLost: number) => {
    if (!stats || !currentProblem) return;
    setStats(prev => {
      if (!prev) return null;
      const newPoints = Math.max(0, prev.points + earnedPoints);
      const newHearts = Math.max(0, prev.hearts - heartsLost);
      const newSolvedCount = prev.solvedCount + 1;
      const newLevel = Math.floor(newPoints / 500) + 1;

      const newSubProg = { ...(prev.subjectProgress || {}) };
      const sub = currentProblem.subject;
      newSubProg[sub] = (newSubProg[sub] || 0) + 1;

      let tempStats = { 
        ...prev, 
        points: newPoints, 
        hearts: newHearts, 
        solvedCount: newSolvedCount, 
        level: newLevel,
        subjectProgress: newSubProg
      };
      tempStats.achievements = checkAchievements(tempStats);
      return tempStats;
    });
    setView('dashboard');
    setCurrentProblem(null);
  };

  const t = TRANSLATIONS[lang];

  return (
    <div className="min-h-screen pb-10 flex flex-col bg-slate-50">
      {stats && <Header stats={stats} lang={lang} onLanguageChange={setLang} onViewChange={setView} />}

      <main className="container mx-auto flex-grow px-4">
        {isGenerating && (
          <div className="fixed inset-0 z-[60] bg-white/95 flex flex-col items-center justify-center p-10 text-center backdrop-blur-md animate-fade-in">
            <div className="w-24 h-24 mb-6 relative">
               <div className="absolute inset-0 border-4 border-blue-600 rounded-full border-t-transparent animate-spin"></div>
               <div className="absolute inset-0 flex items-center justify-center text-5xl animate-bounce">🤖</div>
            </div>
            <h2 className="text-3xl font-bold text-slate-800 mb-3">{t.loading}</h2>
          </div>
        )}

        {view === 'auth' && !stats && <AuthView onAuth={handleAuth} lang={lang} />}

        {stats && view === 'dashboard' && (
          <Dashboard stats={stats} lang={lang} onStartLesson={startLesson} onViewChange={setView} />
        )}

        {stats && view === 'profile' && (
          <ProfileView stats={stats} lang={lang} onLogout={handleLogout} />
        )}

        {stats && view === 'lesson' && currentProblem && (
          <LessonView 
            problem={currentProblem} 
            lang={lang}
            userHearts={stats.hearts}
            onFinish={handleLessonFinish}
            onExit={() => setView('dashboard')}
          />
        )}

        {stats && view === 'parent' && <ParentDashboard stats={stats} lang={lang} />}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { TRANSLATIONS } from '../constants';
import { Language } from '../types';

interface AuthViewProps {
  onAuth: (email: string, password: string, name: string, isNew: boolean) => void;
  lang: Language;
}

const AuthView: React.FC<AuthViewProps> = ({ onAuth, lang }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [name, setName] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);

  const t = TRANSLATIONS[lang];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const trimmedEmail = email.trim();
    const trimmedPassword = password.trim();
    const trimmedName = name.trim();

    if (!trimmedEmail || !trimmedPassword) {
      alert(t.authError);
      return;
    }

    if (!isLogin && !trimmedName) {
      alert(t.authError);
      return;
    }

    setLoading(true);
    // Use setTimeout to allow UI feedback
    setTimeout(() => {
      onAuth(trimmedEmail, trimmedPassword, trimmedName, !isLogin);
      setLoading(false);
    }, 300);
  };

  return (
    <div className="min-h-[80vh] flex flex-col items-center justify-center p-4">
      <div className="bg-white p-8 sm:p-10 rounded-[40px] shadow-2xl shadow-blue-100 max-w-md w-full border border-blue-50 animate-fade-in relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-blue-400 to-cyan-400"></div>

        <div className="w-20 h-20 bg-blue-600 rounded-[28px] mx-auto mb-6 flex items-center justify-center text-white text-4xl shadow-xl shadow-blue-200">
          🤖
        </div>

        <h1 className="text-3xl font-bold text-slate-800 mb-2 text-center">
          {isLogin ? t.login : t.signup}
        </h1>
        <p className="text-slate-500 text-center mb-8 font-medium">BILIMAI - Future NIS Student</p>

        <form onSubmit={handleSubmit} className="space-y-4">
          {!isLogin && (
            <div className="animate-fade-in">
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2 ml-1">{t.enterName}</label>
              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="Alisher"
                autoComplete="name"
                className="w-full p-4 rounded-2xl border-2 border-slate-100 focus:border-blue-500 focus:ring-4 focus:ring-blue-50 outline-none transition-all"
                required={!isLogin}
              />
            </div>
          )}

          <div>
            <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2 ml-1">{t.email}</label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="example@mail.com"
              autoComplete="email"
              className="w-full p-4 rounded-2xl border-2 border-slate-100 focus:border-blue-500 focus:ring-4 focus:ring-blue-50 outline-none transition-all"
              required
            />
          </div>

          <div>
            <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2 ml-1">{t.password}</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••"
              autoComplete={isLogin ? "current-password" : "new-password"}
              className="w-full p-4 rounded-2xl border-2 border-slate-100 focus:border-blue-500 focus:ring-4 focus:ring-blue-50 outline-none transition-all"
              required
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            className={`w-full bg-blue-600 text-white font-bold py-5 rounded-2xl shadow-lg hover:bg-blue-700 hover:-translate-y-1 active:scale-95 transition-all mt-4 flex items-center justify-center ${loading ? 'opacity-70 cursor-not-allowed' : ''}`}
          >
            {loading ? (
              <div className="w-6 h-6 border-3 border-white border-t-transparent animate-spin rounded-full"></div>
            ) : (
              isLogin ? t.login : t.letsGo
            )}
          </button>
        </form>

        <button
          onClick={() => {
            setIsLogin(!isLogin);
            setLoading(false);
          }}
          className="w-full text-center mt-6 text-sm font-bold text-blue-600 hover:text-blue-800 transition-colors"
        >
          {isLogin ? t.noAccount : t.haveAccount}
        </button>
      </div>
    </div>
  );
};

export default AuthView;
